// Minimal offline Bootstrap-compatible tab toggle for this UI
(function () {
  function emit(el, name, detail) {
    if (!el) return;
    var ev = new CustomEvent(name, { bubbles: true, cancelable: true, detail: detail || {} });
    el.dispatchEvent(ev);
  }

  function activate(tabBtn) {
    var target = tabBtn.getAttribute("data-bs-target");
    if (!target || target.charAt(0) !== "#") return;

    var tabs = tabBtn.closest("[role='tablist']");
    var prevBtn = null;
    var prevPane = null;
    if (tabs) {
      prevBtn = tabs.querySelector("[data-bs-toggle='tab'].active");
      tabs.querySelectorAll("[data-bs-toggle='tab']").forEach(function (b) {
        b.classList.remove("active");
        b.setAttribute("aria-selected", "false");
      });
    }
    tabBtn.classList.add("active");
    tabBtn.setAttribute("aria-selected", "true");

    var container = document.querySelector("#configTabsContent") || document;
    prevPane = container.querySelector(".tab-pane.active");
    container.querySelectorAll(".tab-pane").forEach(function (pane) { pane.classList.remove("show", "active"); });
    var pane = document.querySelector(target);
    if (pane) pane.classList.add("show", "active");

    if (prevBtn && prevBtn !== tabBtn) {
      emit(prevBtn, "hidden.bs.tab", { relatedTarget: tabBtn });
    }
    emit(tabBtn, "shown.bs.tab", { relatedTarget: prevBtn });
  }

  document.addEventListener("click", function (ev) {
    var btn = ev.target.closest("[data-bs-toggle='tab']");
    if (!btn) return;
    ev.preventDefault();
    activate(btn);
  });

  document.addEventListener("DOMContentLoaded", function () {
    var btn = document.querySelector("[data-bs-toggle='tab'].active") ||
              document.querySelector("[data-bs-toggle='tab']");
    if (btn) activate(btn);
  });
})();
